import{_ as h,o as i,c as a,ae as t}from"./chunks/framework.BeVX27ge.js";const d=JSON.parse('{"title":"Đánh giá & Phản hồi","description":"","frontmatter":{},"headers":[],"relativePath":"evaluation.md","filePath":"evaluation.md"}'),o={name:"evaluation.md"};function c(g,n,r,u,e,l){return i(),a("div",null,[...n[0]||(n[0]=[t('<h1 id="đanh-gia-phan-hoi" tabindex="-1">Đánh giá &amp; Phản hồi <a class="header-anchor" href="#đanh-gia-phan-hoi" aria-label="Permalink to &quot;Đánh giá &amp; Phản hồi&quot;">​</a></h1><blockquote><p>Nhận phản hồi chuyên môn, chi tiết từng câu nói đến toàn bộ cuộc trò chuyện.</p></blockquote><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Sau mỗi bài thực hành, AI Coach tự động tạo một báo cáo đánh giá chi tiết với 3 cấp độ phân tích:</p><ol><li><strong>Đánh giá Giai đoạn</strong> — Việc hoàn thành các giai đoạn bán hàng và gợi ý cải thiện.</li><li><strong>Đánh giá Toàn diện</strong> — Tóm tắt hiệu suất tổng thể và định hướng học tập.</li><li><strong>Đánh giá Từng câu</strong> — Phân tích chi tiết từng tin nhắn.</li></ol><hr><h2 id="qua-trinh-tao-bao-cao" tabindex="-1">Quá trình Tạo Báo cáo <a class="header-anchor" href="#qua-trinh-tao-bao-cao" aria-label="Permalink to &quot;Quá trình Tạo Báo cáo&quot;">​</a></h2><h3 id="thoi-điem-kich-hoat" tabindex="-1">Thời điểm Kích hoạt <a class="header-anchor" href="#thoi-điem-kich-hoat" aria-label="Permalink to &quot;Thời điểm Kích hoạt&quot;">​</a></h3><p>Khi bạn nhấp &quot;Kết thúc trò chuyện&quot;, hệ thống sẽ: Đóng trò chuyện → Kích hoạt 3 tác vụ nền:</p><ul><li>Tạo Đánh giá Giai đoạn</li><li>Tạo Đánh giá Toàn diện</li><li>Tạo Tóm tắt Cuộc gọi</li></ul><blockquote><p>Lưu ý: Đánh giá Từng câu được tạo ở chế độ nền trong suốt quá trình trò chuyện, ngay sau mỗi tin nhắn.</p></blockquote><h3 id="trang-thai-giao-dien" tabindex="-1">Trạng thái Giao diện <a class="header-anchor" href="#trang-thai-giao-dien" aria-label="Permalink to &quot;Trạng thái Giao diện&quot;">​</a></h3><p>Quá trình tạo thường mất từ 30 giây đến 2 phút.</p><hr><h2 id="_1-đanh-gia-giai-đoan" tabindex="-1">1. Đánh giá Giai đoạn <a class="header-anchor" href="#_1-đanh-gia-giai-đoan" aria-label="Permalink to &quot;1. Đánh giá Giai đoạn&quot;">​</a></h2><p>AI đánh giá toàn bộ cuộc trò chuyện một lần dựa trên các tiêu chuẩn do quản trị viên thiết lập để xác định bạn đã đạt đến giai đoạn bán hàng nào.</p><h3 id="đau-ra" tabindex="-1">Đầu ra <a class="header-anchor" href="#đau-ra" aria-label="Permalink to &quot;Đầu ra&quot;">​</a></h3><p>Đối với mỗi giai đoạn đạt được, thẻ đánh giá sẽ cung cấp phân tích. Nếu bạn không thể thăng cấp lên giai đoạn tiếp theo, một phần &quot;Lý do Không Thăng cấp&quot; sẽ giải thích những gì bạn cần cải thiện.</p><hr><h2 id="_2-đanh-gia-toan-dien" tabindex="-1">2. Đánh giá Toàn diện <a class="header-anchor" href="#_2-đanh-gia-toan-dien" aria-label="Permalink to &quot;2. Đánh giá Toàn diện&quot;">​</a></h2><p>Không giống Đánh giá Giai đoạn, Đánh giá Toàn diện xem xét màn thể hiện của bạn từ góc độ kỹ năng mềm: chất lượng hội thoại, kỹ năng bán hàng, tạo dựng mối quan hệ, và thể hiện sự chuyên nghiệp.</p><h3 id="đau-ra-1" tabindex="-1">Đầu ra <a class="header-anchor" href="#đau-ra-1" aria-label="Permalink to &quot;Đầu ra&quot;">​</a></h3><p>Báo cáo bằng Markdown bao gồm:</p><ul><li>Tổng quan hiệu suất</li><li>Đánh giá Điểm mạnh</li><li>Lĩnh vực Cần Cải thiện</li><li>Đề xuất Bước đi Tiếp theo</li></ul><hr><h2 id="_3-đanh-gia-tung-cau" tabindex="-1">3. Đánh giá Từng câu <a class="header-anchor" href="#_3-đanh-gia-tung-cau" aria-label="Permalink to &quot;3. Đánh giá Từng câu&quot;">​</a></h2><p>Cấp độ phản hồi chi tiết nhất, phân tích từng tin nhắn của bạn đang diễn ra.</p><h3 id="cach-thuc-hoat-đong" tabindex="-1">Cách thức Hoạt động <a class="header-anchor" href="#cach-thuc-hoat-đong" aria-label="Permalink to &quot;Cách thức Hoạt động&quot;">​</a></h3><p>Tính năng này chạy ngầm trong suốt buổi thực hành. Khi bạn chuyển sang tab Đánh giá Từng câu, bạn có thể xem lại &quot;Suy nghĩ nội tâm của AI&quot; (điều khách hàng đang thực sự nghĩ) và các phản hồi chi tiết cho từng tin nhắn (cách diễn đạt, hiệu quả sử dụng kỹ năng).</p><hr><h2 id="cung-cap-phan-hoi-cho-phan-tich-cua-ai" tabindex="-1">Cung cấp Phản hồi cho Phân tích của AI <a class="header-anchor" href="#cung-cap-phan-hoi-cho-phan-tich-cua-ai" aria-label="Permalink to &quot;Cung cấp Phản hồi cho Phân tích của AI&quot;">​</a></h2><p>Bên dưới Đánh giá Toàn diện và mỗi mục Từng câu, bạn có thể nhấn Thích/Không Thích để cung cấp phản hồi về chất lượng phân tích của hệ thống AI, qua đó giúp cải thiện hệ thống trong tương lai.</p><h2 id="loi-khuyen" tabindex="-1">Lời khuyên <a class="header-anchor" href="#loi-khuyen" aria-label="Permalink to &quot;Lời khuyên&quot;">​</a></h2><ol><li>Đọc <strong>Đánh giá Giai đoạn</strong> để biết bạn đã làm tốt ở bước nào.</li><li>Kiểm tra phần <strong>Không thăng cấp</strong> để xem thiếu sót.</li><li>Đọc <strong>Đánh giá Toàn diện</strong> để biết định hướng.</li><li>Nhấc tab <strong>Đánh giá Từng câu</strong> và chú ý phần <strong>Suy nghĩ nội tâm của AI</strong> để thấu hiểu tâm lý khách hàng.</li></ol>',34)])])}const s=h(o,[["render",c]]);export{d as __pageData,s as default};
